// Extract market questions and current prices from Polymarket
const markets = $input.all();
const polymarketData = [];

for (const item of markets) {
  const m = item.json;
  const question = m.question || m.title || '';
  const outcomes = typeof m.outcomes === 'string' ? JSON.parse(m.outcomes) : (m.outcomes || []);
  const prices = typeof m.outcomePrices === 'string' ? JSON.parse(m.outcomePrices) : (m.outcomePrices || []);

  // Extract team names from the question
  // Common patterns: "Will X win?", "X vs Y", "Will X beat Y?"
  const teamNames = [];
  for (let i = 0; i < outcomes.length; i++) {
    teamNames.push({
      outcome: outcomes[i],
      price: Number(prices[i] || 0),
      impliedProb: Number(prices[i] || 0) * 100
    });
  }

  polymarketData.push({
    json: {
      question,
      conditionId: m.conditionId || '',
      slug: m.slug || '',
      outcomes: teamNames
    }
  });
}

return polymarketData;

// Match Polymarket markets to sportsbook odds and find edges
const EDGE_THRESHOLD = 0.05; // 5% minimum edge to alert

const polymarketItems = $('Extract Market Prices').all();
const oddsResponse = $input.all();
const sportsEvents = Array.isArray(oddsResponse[0]?.json) ? oddsResponse[0].json : oddsResponse.map(i => i.json);

const edges = [];

// Build a lookup of sportsbook implied probabilities
const sportsbookProbs = {};
for (const event of sportsEvents) {
  if (!event.bookmakers || event.bookmakers.length === 0) continue;

  // Average across bookmakers for best estimate
  const teamProbs = {};
  let bookCount = 0;

  for (const book of event.bookmakers) {
    for (const market of (book.markets || [])) {
      if (market.key !== 'h2h') continue;
      bookCount++;
      for (const outcome of (market.outcomes || [])) {
        const name = outcome.name.toLowerCase();
        const decimalOdds = outcome.price || 2.0;
        const impliedProb = 1 / decimalOdds;
        teamProbs[name] = (teamProbs[name] || 0) + impliedProb;
      }
    }
  }

  // Average the probabilities
  if (bookCount > 0) {
    for (const team in teamProbs) {
      teamProbs[team] = teamProbs[team] / bookCount;
    }
  }

  sportsbookProbs[event.home_team?.toLowerCase()] = teamProbs;
  sportsbookProbs[event.away_team?.toLowerCase()] = teamProbs;
}

// Compare Polymarket prices to sportsbook probabilities
for (const pm of polymarketItems) {
  const question = (pm.json.question || '').toLowerCase();
  const outcomes = pm.json.outcomes || [];

  for (const outcome of outcomes) {
    const outcomeName = (outcome.outcome || '').toLowerCase();
    const polyProb = outcome.impliedProb / 100;

    // Try to find matching sportsbook data
    for (const key in sportsbookProbs) {
      if (question.includes(key) || outcomeName.includes(key)) {
        const sbProbs = sportsbookProbs[key];
        for (const team in sbProbs) {
          if (outcomeName.includes(team) || team.includes(outcomeName)) {
            const sbProb = sbProbs[team];
            const diff = Math.abs(polyProb - sbProb);

            if (diff >= EDGE_THRESHOLD) {
              const direction = polyProb < sbProb ? 'Polymarket UNDERPRICED' : 'Polymarket OVERPRICED';
              edges.push({
                json: {
                  market: pm.json.question,
                  outcome: outcome.outcome,
                  polymarketPrice: (polyProb * 100).toFixed(1) + '%',
                  sportsbookImplied: (sbProb * 100).toFixed(1) + '%',
                  edge: (diff * 100).toFixed(1) + '%',
                  direction,
                  alertMessage: `Edge Found: ${pm.json.question}\n${outcome.outcome}: Polymarket ${(polyProb * 100).toFixed(1)}% vs Sportsbook ${(sbProb * 100).toFixed(1)}%\nEdge: ${(diff * 100).toFixed(1)}% -- ${direction}`
                }
              });
            }
          }
        }
      }
    }
  }
}

if (edges.length === 0) {
  return [{ json: { _skip: true } }];
}

return edges;
